INSERT INTO group_join_request (
    group_id, user_key, status, requested_at
) VALUES (
    #{groupId}, #{userKey}, 'PENDING', NOW()
)

mapper.select:
SELECT request_id, group_id, user_key, status, requested_at, approved_at, reject_reason
FROM group_join_request
WHERE request_id = #{requestId}

mapper.update:
UPDATE group_join_request
SET status='APPROVED', approved_at = NOW()
WHERE request_id = #{requestId}

UPDATE group_join_request
SET status='REJECTED', reject_reason = #{rejectReason}
WHERE request_id = #{requestId}

UPDATE group_join_request
SET status='CANCELLED'
WHERE request_id = #{requestId}
AND user_key = #{userKey}
